function buildBaseQuery(queryParams) {
  const queryKeys = Object.keys(queryParams);

  if (queryKeys.length === 1) {
    const key = queryKeys[0];
    return { [key]: queryParams[key] };
  }

  // Multiple query types → wrap in bool.must
  const mustClauses = queryKeys.map((key) => ({ [key]: queryParams[key] }));
  return {
    bool: {
      must: mustClauses,
    },
  };
}

function applyFilters(baseQuery, filters) {
  if (!filters) return baseQuery;

  const boolQuery = baseQuery.bool ? { ...baseQuery.bool } : { must: [baseQuery] };

  if (filters.must) {
    boolQuery.must = [...(boolQuery.must || []), ...filters.must];
  }
  if (filters.must_not) {
    boolQuery.must_not = [...(boolQuery.must_not || []), ...filters.must_not];
  }
  if (filters.should) {
    boolQuery.should = [...(boolQuery.should || []), ...filters.should];
  }
  if (filters.filter) {
    boolQuery.filter = [...(boolQuery.filter || []), ...filters.filter];
  }

  return { bool: boolQuery };
}

function buildScoringQuery(baseQuery, scoring) {
  if (!scoring) return baseQuery;

  // If only script_score is needed (simple case)
  if (scoring.script && !scoring.score_functions && !scoring.field_value_factor && !scoring.decay_functions) {
    const scriptScoreQuery = {
      script_score: {
        query: baseQuery,
        script: {
          source: scoring.script.source,
          lang: scoring.script.lang || 'painless',
        },
      },
    };

    if (scoring.script.params) {
      scriptScoreQuery.script_score.script.params = scoring.script.params;
    }

    if (scoring.min_score !== undefined) {
      scriptScoreQuery.script_score.min_score = scoring.min_score;
    }

    return scriptScoreQuery;
  }

  // function_score for complex scoring
  const functionScoreQuery = {
    function_score: {
      query: baseQuery,
      functions: [],
    },
  };

  if (scoring.boost_mode) {
    functionScoreQuery.function_score.boost_mode = scoring.boost_mode;
  }

  if (scoring.max_boost !== undefined) {
    functionScoreQuery.function_score.max_boost = scoring.max_boost;
  }

  if (scoring.min_score !== undefined) {
    functionScoreQuery.function_score.min_score = scoring.min_score;
  }

  // Add field_value_factor
  if (scoring.field_value_factor) {
    functionScoreQuery.function_score.functions.push({
      field_value_factor: scoring.field_value_factor,
    });
  }

  // Add decay functions
  if (scoring.decay_functions) {
    for (const decay of scoring.decay_functions) {
      const decayFn = {};
      const decayType = decay.type; // linear, exp, gauss
      decayFn[decayType] = {
        [decay.field]: {
          origin: decay.origin,
          scale: decay.scale,
        },
      };
      if (decay.offset) {
        decayFn[decayType][decay.field].offset = decay.offset;
      }
      if (decay.decay !== undefined) {
        decayFn[decayType][decay.field].decay = decay.decay;
      }
      functionScoreQuery.function_score.functions.push(decayFn);
    }
  }

  // Add script as a scoring function
  if (scoring.script) {
    const scriptFn = {
      script_score: {
        script: {
          source: scoring.script.source,
          lang: scoring.script.lang || 'painless',
        },
      },
    };
    if (scoring.script.params) {
      scriptFn.script_score.script.params = scoring.script.params;
    }
    functionScoreQuery.function_score.functions.push(scriptFn);
  }

  // Add custom score functions
  if (scoring.score_functions) {
    for (const fn of scoring.score_functions) {
      const scoreFn = {};

      if (fn.filter) {
        scoreFn.filter = fn.filter;
      }
      if (fn.weight !== undefined) {
        scoreFn.weight = fn.weight;
      }
      if (fn.script_score) {
        scoreFn.script_score = {
          script: {
            source: fn.script_score.source,
            lang: fn.script_score.lang || 'painless',
          },
        };
        if (fn.script_score.params) {
          scoreFn.script_score.script.params = fn.script_score.params;
        }
      }
      if (fn.field_value_factor) {
        scoreFn.field_value_factor = fn.field_value_factor;
      }

      functionScoreQuery.function_score.functions.push(scoreFn);
    }
  }

  return functionScoreQuery;
}

function buildElasticsearchQuery(params) {
  let baseQuery = buildBaseQuery(params.query);

  // Apply filters
  baseQuery = applyFilters(baseQuery, params.filters);

  // Validate all scripts in scoring
  if (params.scoring) {
    if (params.scoring.script) {
      const validation = validateScript(params.scoring.script.source);
      if (!validation.valid) {
        throw new Error(`Invalid scoring script: ${validation.reason}`);
      }
    }
    if (params.scoring.score_functions) {
      for (const fn of params.scoring.score_functions) {
        if (fn.script_score) {
          const validation = validateScript(fn.script_score.source);
          if (!validation.valid) {
            throw new Error(`Invalid score function script: ${validation.reason}`);
          }
        }
      }
    }
  }

  // Apply scoring
  const scoredQuery = buildScoringQuery(baseQuery, params.scoring);

  // Build the full request body
  const body = {
    query: scoredQuery,
    from: params.pagination.from,
    size: params.pagination.size,
  };

  if (params.sort) {
    body.sort = params.sort;
  }

  if (params.aggregations) {
    body.aggs = params.aggregations;
  }

  if (params.highlight) {
    body.highlight = params.highlight;
  }

  if (params.source !== undefined) {
    body._source = params.source;
  }

  if (params.collapse) {
    body.collapse = params.collapse;
  }

  if (params.suggest) {
    body.suggest = params.suggest;
  }

  return body;
}

