// Main search endpoint
app.post('/api/search', async (req, res) => {
  try {
    const { error, value: params } = searchParamsSchema.validate(req.body, {
      abortEarly: false,
      stripUnknown: true,
    });

    if (error) {
      return res.status(400).json({
        status: 'error',
        message: 'Validation failed',
        details: error.details.map((d) => d.message),
      });
    }

    const esQueryBody = buildElasticsearchQuery(params);

    console.log('Elasticsearch Query DSL:', JSON.stringify(esQueryBody, null, 2));

    const response = await esClient.search({
      index: params.index,
      body: esQueryBody,
    });

    const result = {
      status: 'ok',
      took: response.took,
      timed_out: response.timed_out,
      total: response.hits.total,
      max_score: response.hits.max_score,
      hits: response.hits.hits.map((hit) => ({
        id: hit._id,
        index: hit._index,
        score: hit._score,
        source: hit._source,
        highlight: hit.highlight || undefined,
        sort: hit.sort || undefined,
        inner_hits: hit.inner_hits || undefined,
      })),
    };

    if (response.aggregations) {
      result.aggregations = response.aggregations;
    }

    if (response.suggest) {
      result.suggest = response.suggest;
    }

    res.json(result);
  } catch (error) {
    console.error('Search error:', error);

    if (error.message && error.message.startsWith('Invalid')) {
      return res.status(400).json({
        status: 'error',
        message: error.message,
      });
    }

    const statusCode = error.statusCode || 500;
    res.status(statusCode).json({
      status: 'error',
      message: error.message || 'Internal server error',
      details: error.meta?.body?.error || undefined,
    });
  }
});

