// Multi-search endpoint for batch queries
app.post('/api/search/multi', async (req, res) => {
  try {
    const { searches } = req.body;

    if (!Array.isArray(searches) || searches.length === 0) {
      return res.status(400).json({
        status: 'error',
        message: 'searches must be a non-empty array',
      });
    }

    if (searches.length > 20) {
      return res.status(400).json({
        status: 'error',
        message: 'Maximum 20 searches allowed per batch',
      });
    }

    const bulkBody = [];
    const validationErrors = [];

    for (let i = 0; i < searches.length; i++) {
      const { error, value: params } = searchParamsSchema.validate(searches[i], {
        abortEarly: false,
        stripUnknown: true,
      });

      if (error) {
        validationErrors.push({
          index: i,
          errors: error.details.map((d) => d.message),
        });
        continue;
      }

      try {
        const esQueryBody = buildElasticsearchQuery(params);
        bulkBody.push({ index: params.index });
        bulkBody.push(esQueryBody);
      } catch (buildError) {
        validationErrors.push({
          index: i,
          errors: [buildError.message],
        });
      }
    }

    if (validationErrors.length > 0) {
      return res.status(400).json({
        status: 'error',
        message: 'Validation failed for one or more searches',
        validation_errors: validationErrors,
      });
    }

    const response = await esClient.msearch({ body: bulkBody });

    const results = response.responses.map((r, idx) => {
      if (r.error) {
        return {
          status: 'error',
          error: r.error,
        };
      }
      return {
        status: 'ok',
        took: r.took,
        total: r.hits.total,
        max_score: r.hits.max_score,
        hits: r.hits.hits.map((hit) => ({
          id: hit._id,
          index: hit._index,
          score: hit._score,
          source: hit._source,
          highlight: hit.highlight || undefined,
        })),
        aggregations: r.aggregations || undefined,
      };
    });

    res.json({
      status: 'ok',
      took: response.took,
      results,
    });
  } catch (error) {
    console.error('Multi-search error:', error);
    res.status(error.statusCode || 500).json({
      status: 'error',
      message: error.message,
    });
  }
});

// Explain endpoint - explains scoring for a specific document
app.post('/api/search/explain', async (req, res) => {
  try {
    const { index, document_id, ...searchParams } = req.body;

    if (!index || !document_id) {
      return res.status(400).json({
        status: 'error',
        message: 'index and document_id are required',
      });
    }

    const { error, value: params } = searchParamsSchema.validate(
      { index, ...searchParams },
      { abortEarly: false, stripUnknown: true }
    );

    if (error) {
      return res.status(400).json({
        status: 'error',
        message: 'Validation failed',
        details: error.details.map((d) => d.message),
      });
    }

    const esQueryBody = buildElasticsearchQuery(params);

    const response = await esClient.explain({
      index,
      id: document_id,
      body: { query: esQueryBody.query },
    });

    res.json({
      status: 'ok',
      matched: response.matched,
      explanation: response.explanation,
    });
  } catch (error) {
    console.error('Explain error:', error);
    res.status(error.statusCode || 500).json({
      status: 'error',
      message: error.message,
    });
  }
});

// Index management - create index with mappings
app.post('/api/indices', async (req, res) => {
  try {
    const { index, mappings, settings } = req.body;

    if (!index) {
      return res.status(400).json({
        status: 'error',
        message: 'index name is required',
      });
    }

    const body = {};
    if (mappings) body.mappings = mappings;
    if (settings) body.settings = settings;

    const response = await esClient.indices.create({
      index,
      body,
    });

    res.json({
      status: 'ok',
      acknowledged: response.acknowledged,
      index: response.index,
    });
  } catch (error) {
    res.status(error.statusCode || 500).json({
      status: 'error',
      message: error.message,
    });
  }
});

// Index a document
app.post('/api/documents/:index', async (req, res) => {
  try {
    const { index } = req.params;
    const { id, document } = req.body;

    if (!document) {
      return res.status(400).json({
        status: 'error',
        message: 'document body is required',
      });
    }

    const params = {
      index,
      body: document,
      refresh: 'wait_for',
    };

    if (id) {
      params.id = id;
    }

    const response = await esClient.index(params);

    res.json({
      status: 'ok',
      id: response._id,
      index: response._index,
      result: response.result,
    });
  } catch (error) {
    res.status(error.statusCode || 500).json({
      status: 'error',
      message: error.message,
    });
  }
});

// Bulk index documents
app.post('/api/documents/:index/bulk', async (req, res) => {
  try {
    const { index } = req.params;
    const { documents } = req.body;

    if (!Array.isArray(documents) || documents.length === 0) {
      return res.status(400).json({
        status: 'error',
        message: 'documents must be a non-empty array',
      });
    }

    const bulkBody = [];
    for (const doc of documents) {
      const action = { index: { _index: index } };
      if (doc.id) {
        action.index._id = doc.id;
      }
      bulkBody.push(action);
      bulkBody.push(doc.body || doc);
    }

    const response = await esClient.bulk({
      body: bulkBody,
      refresh: 'wait_for',
    });

    res.json({
      status: 'ok',
      took: response.took,
      errors: response.errors,
      items: response.items.map((item) => ({
        id: item.index._id,
        result: item.index.result,
        status: item.index.status,
        error: item.index.error || undefined,
      })),
    });
  } catch (error) {
    res.status(error.statusCode || 500).json({
      status: 'error',
      message: error.message,
    });
  }
});

// Error handling middleware
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);
  res.status(500).json({
    status: 'error',
    message: 'Internal server error',
  });
});

const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Enterprise Search Platform running on port ${PORT}`);
  console.log(`Elasticsearch node: ${process.env.ELASTICSEARCH_URL || 'http://localhost:9200'}`);
});

module.exports = {
  app,
  buildElasticsearchQuery,
  buildBaseQuery,
  applyFilters,
  buildScoringQuery,
  validateScript,
};